<template><section class="panel"><div class="panel-header"><h2>平台账号</h2><div style="display:flex;gap:8px"><button v-if="!showForm" class="ghost" @click="showForm=true">+ 新增</button><button v-else class="ghost" @click="showForm=false">收起</button><button class="ghost" @click="load">刷新</button></div></div><p v-if="!token" class="hint">需要登录</p><template v-if="showForm&&token"><div class="form-grid"><label>平台<select v-model="form.platformId"><option value="boss">Boss直聘</option><option value="zhaopin">智联招聘</option><option value="liepin">猎聘</option></select></label><label>名称<input v-model="form.displayName" placeholder="我的Boss"/></label></div><p v-if="msg" :class="msgType">{{msg}}</p><div class="actions"><button :disabled="loading||!form.displayName" @click="create">{{loading?'处理中...':'创建'}}</button></div></template><p v-if="accounts.length===0" class="hint">暂无账号</p><div v-else class="card-list" style="margin-top:8px"><article v-for="a in accounts" :key="a.id" class="card"><div><strong>{{a.display_name||a.id}}</strong><p class="card-meta">{{a.platform_id}} | cookie:{{a.cookie_status||'无'}}</p></div><button class="ghost danger" @click="del(a)">删除</button></article></div></section></template><script setup lang="ts">import{onMounted,ref}from'vue';const props=defineProps<{token:string;agentBaseUrl:string}>();const accounts=ref<any[]>([]);const loading=ref(false);const msg=ref('');const msgType=ref('error');const form=ref({platformId:'boss',displayName:''});const showForm=ref(false);const api=(p:string,o?:RequestInit)=>fetch(`${(window as any).GOODHR_CLOUD_API||'http://127.0.0.1:8084'}${p}`,{headers:{Authorization:`Bearer ${props.token}`,'Content-Type':'application/json',...o?.headers},...o}).then(r=>r.json());async function load(){try{const d=await api('/api/platform-accounts');const list:any[]=d.accounts||[];let cookies:any[]=[];try{const c=await api('/api/cookies');cookies=c.cookies||[]}catch{}for(const a of list){const m=cookies.find((x:any)=>x.platform_id===a.platform_id);if(m)a.cookie_status=m.status}accounts.value=list}catch{}}async function create(){loading.value=true;msg.value='';try{const d=await api('/api/platform-accounts/create',{method:'POST',body:JSON.stringify({platform_id:form.value.platformId,display_name:form.value.displayName,local_profile_id:form.value.displayName})});if(!d.ok){msg.value=d.error||'失败';msgType.value='error';return}if(props.agentBaseUrl)await api('/api/cookies/create',{method:'POST',headers:Object.assign({},{'X-GoodHR-Agent-BaseURL':props.agentBaseUrl})as any,body:JSON.stringify({platform_id:form.value.platformId,display_name:form.value.displayName})});form.value.displayName='';msg.value='创建成功';msgType.value='success';await load()}catch(e:any){msg.value=e.message;msgType.value='error'}finally{loading.value=false}}async function del(a:any){try{await api(`/api/platform-accounts/${a.id}`,{method:'DELETE'})}catch{}await load()}onMounted(load)</script>